// reactapp/src/components/AppointmentList.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import "./AppointmentList.css";

export default function AppointmentList() {
  const [patients, setPatients] = useState([]);
  const [selectedName, setSelectedName] = useState("");
  const [appointments, setAppointments] = useState([]);
  const [loadingPatients, setLoadingPatients] = useState(false);
  const [loadingAppointments, setLoadingAppointments] = useState(false);
  const [error, setError] = useState("");
  const apiBase = process.env.REACT_APP_API_URL || "http://localhost:8080";

  useEffect(() => {
    let mounted = true;
    setLoadingPatients(true);
    setError("");
    axios.get(`${apiBase}/api/patients`)
      .then(res => {
        if (!mounted) return;
        const list = Array.isArray(res.data) ? res.data : [];
        setPatients(list);
      })
      .catch(err => {
        console.error("fetch patients error:", err);
        if (mounted) setPatients([]);
        setError("Could not load patients");
      })
      .finally(() => mounted && setLoadingPatients(false));
    return () => { mounted = false; };
  }, [apiBase]);

  useEffect(() => {
    if (!selectedName) {
      setAppointments([]);
      return;
    }
    let mounted = true;
    setLoadingAppointments(true);
    setError("");
    axios.get(`${apiBase}/api/appointments/patient`, { params: { name: selectedName } })
      .then(res => {
        if (!mounted) return;
        setAppointments(Array.isArray(res.data) ? res.data : []);
      })
      .catch(err => {
        console.error("fetch appointments error:", err);
        if (mounted) setAppointments([]);
        setError("Could not load appointments");
      })
      .finally(() => mounted && setLoadingAppointments(false));
    return () => { mounted = false; };
  }, [selectedName, apiBase]);

  return (
    <div>
      <label style={{ display: "block", marginBottom: 8 }} className="field-label">Select patient</label>

      <select
        data-testid="patient-filter"
        className="field-input"
        value={selectedName}
        onChange={(e) => setSelectedName(e.target.value)}
      >
        <option value="">{loadingPatients ? "Loading patients..." : "Select patient"}</option>
        {patients.map(p => (
          // use patient name as the value because backend expects ?name=...
          <option key={p.id} value={p.name}>{p.name}</option>
        ))}
      </select>

      {error && <div className="field-error" style={{ marginTop: 8 }}>{error}</div>}

      {loadingAppointments ? (
        <div style={{ marginTop: 12 }}>Loading appointments...</div>
      ) : appointments.length === 0 ? (
        <div data-testid="no-appointments" style={{ marginTop: 12 }}>
          No appointments
        </div>
      ) : (
        <ul style={{ marginTop: 12 }}>
          {appointments.map((a) => (
            <li key={a.id} style={{ padding: "8px 0", borderBottom: "1px solid #e2e8f0" }}>
              <div><strong>{a.reason}</strong></div>
              <div>{a.appointmentDate} {a.appointmentTime}</div>
              <div>Doctor: {a.doctor?.name || "—"}</div>
              <div>Status: {a.status}</div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
